  SELECT (LOWER(REPLACE(CONCAT('audit-', (SELECT NULLIF(citation, '') FROM audit_log_entries WHERE audit_log_entrie_id = p_audit_log_entrie_id), '-', TO_CHAR(((SELECT timestamp::timestamptz FROM audit_log_entries WHERE audit_log_entrie_id = p_audit_log_entrie_id))::timestamptz AT TIME ZONE 'UTC', 'YYYY-MM-DD"T"HH24-MI-SS'), '-', (SELECT NULLIF(action_type, '') FROM audit_log_entries WHERE audit_log_entrie_id = p_audit_log_entrie_id)), ' ', '-')))::text;
$$ LANGUAGE sql STABLE;

-- calc_audit_log_entries_is_override_action
-- Field: AuditLogEntries.IsOverrideAction
-- Type: calculated | DataType: boolean | Returns: BOOLEAN


CREATE OR REPLACE FUNCTION calc_audit_log_entries_is_override_action(p_audit_log_entrie_id TEXT)
RETURNS BOOLEAN AS $$
  SELECT (CASE WHEN LOWER(CONCAT((SELECT NULLIF(action_type, '') FROM audit_log_entries WHERE audit_log_entrie_id = p_audit_log_entrie_id), '')) = "override" THEN TRUE ELSE FALSE END)::boolean;
$$ LANGUAGE sql STABLE;

-- calc_audit_log_entries_entry_age_hours
-- Field: AuditLogEntries.EntryAgeHours
-- Type: calculated | DataType: integer | Returns: INTEGER


CREATE OR REPLACE FUNCTION calc_audit_log_entries_entry_age_hours(p_audit_log_entrie_id TEXT)
RETURNS INTEGER AS $$
  SELECT ((EXTRACT(EPOCH FROM (CURRENT_TIMESTAMP::timestamp - (SELECT timestamp::timestamptz FROM audit_log_entries WHERE audit_log_entrie_id = p_audit_log_entrie_id)::timestamp)) / 3600))::integer;
$$ LANGUAGE sql STABLE;

