-- calc_jurisdictions_name
-- Field: Jurisdictions.Name
-- Type: calculated | DataType: string | Returns: TEXT

CREATE OR REPLACE FUNCTION calc_jurisdictions_name(p_jurisdiction_id TEXT)
RETURNS TEXT AS $$
  SELECT (CONCAT(LOWER((SELECT NULLIF(state, '') FROM jurisdictions WHERE jurisdiction_id = p_jurisdiction_id)), '-us'))::text;
$$ LANGUAGE sql STABLE;

-- calc_jurisdictions_is_root_jurisdiction
-- Field: Jurisdictions.IsRootJurisdiction
-- Type: calculated | DataType: integer | Returns: INTEGER

CREATE OR REPLACE FUNCTION calc_jurisdictions_is_root_jurisdiction(p_jurisdiction_id TEXT)
RETURNS INTEGER AS $$
  SELECT (CASE WHEN (CASE WHEN (SELECT NULLIF(parent_jurisdiction, '') FROM jurisdictions WHERE jurisdiction_id = p_jurisdiction_id) IS NULL THEN TRUE ELSE FALSE END) THEN 1 ELSE 0 END)::integer;
$$ LANGUAGE sql STABLE;

-- calc_jurisdictions_child_jurisdiction_count
-- Field: Jurisdictions.ChildJurisdictionCount
-- Type: aggregation | DataType: integer | Returns: INTEGER

CREATE OR REPLACE FUNCTION calc_jurisdictions_child_jurisdiction_count(p_jurisdiction_id TEXT)
RETURNS INTEGER AS $$
  SELECT ((SELECT COUNT(*) FROM jurisdictions WHERE parent_jurisdiction = (SELECT NULLIF(jurisdiction_id, '') FROM jurisdictions WHERE jurisdiction_id = p_jurisdiction_id)))::integer;
$$ LANGUAGE sql STABLE;

-- calc_jurisdictions_relative_path
-- Field: Jurisdictions.RelativePath
-- Type: calculated | DataType: string | Returns: TEXT


CREATE OR REPLACE FUNCTION calc_jurisdictions_relative_path(p_jurisdiction_id TEXT)
RETURNS TEXT AS $$
  SELECT (CONCAT('/library/jurisdictions/', (SELECT NULLIF(jurisdiction_id, '') FROM jurisdictions WHERE jurisdiction_id = p_jurisdiction_id)))::text;
$$ LANGUAGE sql STABLE;

-- calc_jurisdictions_rule_count
-- Field: Jurisdictions.RuleCount
-- Type: aggregation | DataType: integer | Returns: INTEGER


CREATE OR REPLACE FUNCTION calc_jurisdictions_rule_count(p_jurisdiction_id TEXT)
RETURNS INTEGER AS $$
  SELECT ((SELECT COUNT(*) FROM jurisdiction_rules WHERE jurisdiction = (SELECT NULLIF(jurisdiction_id, '') FROM jurisdictions WHERE jurisdiction_id = p_jurisdiction_id)))::integer;
$$ LANGUAGE sql STABLE;

-- calc_jurisdictions_source_document_count
-- Field: Jurisdictions.SourceDocumentCount
-- Type: aggregation | DataType: integer | Returns: INTEGER

CREATE OR REPLACE FUNCTION calc_jurisdictions_source_document_count(p_jurisdiction_id TEXT)
RETURNS INTEGER AS $$
  SELECT ((SELECT COUNT(*) FROM jurisdiction_source_documents WHERE jurisdiction = (SELECT NULLIF(jurisdiction_id, '') FROM jurisdictions WHERE jurisdiction_id = p_jurisdiction_id)))::integer;
$$ LANGUAGE sql STABLE;

-- calc_jurisdiction_source_documents_jurisdiction_name
-- Field: JurisdictionSourceDocuments.JurisdictionName
-- Type: lookup | DataType: string | Returns: TEXT
-- Lookup: Name from related Jurisdictions

CREATE OR REPLACE FUNCTION calc_jurisdiction_source_documents_jurisdiction_name(p_jurisdiction_source_document_id TEXT)
RETURNS TEXT AS $$
  SELECT calc_jurisdictions_name((SELECT jurisdiction FROM jurisdiction_source_documents WHERE jurisdiction_source_document_id = p_jurisdiction_source_document_id));
$$ LANGUAGE sql STABLE;

-- calc_jurisdiction_source_documents_name
-- Field: JurisdictionSourceDocuments.Name
-- Type: calculated | DataType: string | Returns: TEXT

CREATE OR REPLACE FUNCTION calc_jurisdiction_source_documents_name(p_jurisdiction_source_document_id TEXT)
RETURNS TEXT AS $$
  SELECT (REPLACE(LOWER((SELECT NULLIF(title, '') FROM jurisdiction_source_documents WHERE jurisdiction_source_document_id = p_jurisdiction_source_document_id)), ' ', '-'))::text;
$$ LANGUAGE sql STABLE;

-- calc_jurisdiction_source_documents_relative_path
-- Field: JurisdictionSourceDocuments.RelativePath
-- Type: calculated | DataType: string | Returns: TEXT


CREATE OR REPLACE FUNCTION calc_jurisdiction_source_documents_relative_path(p_jurisdiction_source_document_id TEXT)
RETURNS TEXT AS $$
  SELECT (CONCAT('/library/jurisdiction-docs/', (SELECT NULLIF(jurisdiction_source_document_id, '') FROM jurisdiction_source_documents WHERE jurisdiction_source_document_id = p_jurisdiction_source_document_id)))::text;
$$ LANGUAGE sql STABLE;

-- calc_jurisdiction_source_documents_rule_count
-- Field: JurisdictionSourceDocuments.RuleCount
-- Type: aggregation | DataType: integer | Returns: INTEGER

CREATE OR REPLACE FUNCTION calc_jurisdiction_source_documents_rule_count(p_jurisdiction_source_document_id TEXT)
RETURNS INTEGER AS $$
  SELECT ((SELECT COUNT(*) FROM jurisdiction_rules WHERE source_document = (SELECT NULLIF(jurisdiction_source_document_id, '') FROM jurisdiction_source_documents WHERE jurisdiction_source_document_id = p_jurisdiction_source_document_id)))::integer;
$$ LANGUAGE sql STABLE;

-- calc_jurisdiction_rules_route_path
-- Field: JurisdictionRules.RoutePath
-- Type: lookup | DataType: string | Returns: TEXT
-- Lookup: Route from related PlatformNaviation


CREATE OR REPLACE FUNCTION calc_jurisdiction_rules_route_path(p_jurisdiction_rule_id TEXT)
