-- calc_jurisdiction_rules_name
-- Field: JurisdictionRules.Name
-- Type: calculated | DataType: string | Returns: TEXT

CREATE OR REPLACE FUNCTION calc_jurisdiction_rules_name(p_jurisdiction_rule_id TEXT)
RETURNS TEXT AS $$
  SELECT (REPLACE(LOWER((SELECT NULLIF(rule_number, '') FROM jurisdiction_rules WHERE jurisdiction_rule_id = p_jurisdiction_rule_id)), ' ', '-'))::text;
$$ LANGUAGE sql STABLE;

-- calc_jurisdiction_rules_relative_path
-- Field: JurisdictionRules.RelativePath
-- Type: calculated | DataType: string | Returns: TEXT


CREATE OR REPLACE FUNCTION calc_jurisdiction_rules_relative_path(p_jurisdiction_rule_id TEXT)
RETURNS TEXT AS $$
  SELECT (CONCAT('/library/jurisdiction-rules/', (SELECT NULLIF(jurisdiction_rule_id, '') FROM jurisdiction_rules WHERE jurisdiction_rule_id = p_jurisdiction_rule_id)))::text;
$$ LANGUAGE sql STABLE;

-- calc_jurisdiction_rules_is_federal
-- Field: JurisdictionRules.IsFederal
-- Type: calculated | DataType: integer | Returns: INTEGER

CREATE OR REPLACE FUNCTION calc_jurisdiction_rules_is_federal(p_jurisdiction_rule_id TEXT)
RETURNS INTEGER AS $$
  SELECT (CASE WHEN (CASE WHEN calc_jurisdiction_rules_jurisdiction_type(p_jurisdiction_rule_id) = 'Country' THEN TRUE ELSE FALSE END) THEN 1 ELSE 0 END)::integer;
$$ LANGUAGE sql STABLE;

