-- calc_erb_tables_name
-- Field: ERBTables.Name
-- Type: calculated | DataType: string | Returns: TEXT


CREATE OR REPLACE FUNCTION calc_erb_tables_name(p_erb_table_id TEXT)
RETURNS TEXT AS $$
  SELECT ((SELECT NULLIF(erb_table_id, '') FROM erb_tables WHERE erb_table_id = p_erb_table_id))::text;
$$ LANGUAGE sql STABLE;

-- calc_erb_tables_admin_can_create
-- Field: ERBTables.AdminCanCreate
-- Type: calculated | DataType: boolean | Returns: BOOLEAN


CREATE OR REPLACE FUNCTION calc_erb_tables_admin_can_create(p_erb_table_id TEXT)
RETURNS BOOLEAN AS $$
  SELECT (CASE WHEN (SELECT NULLIF(admin_crud, '') FROM erb_tables WHERE erb_table_id = p_erb_table_id) IS NULL THEN (NULL)::text ELSE (NOT (((POSITION('C' IN (SELECT NULLIF(admin_crud, '') FROM erb_tables WHERE erb_table_id = p_erb_table_id))) = 0)))::text END)::boolean;
$$ LANGUAGE sql STABLE;

