-- calc_subject_state_instances_name
-- Field: SubjectStateInstances.Name
-- Type: calculated | DataType: string | Returns: TEXT


CREATE OR REPLACE FUNCTION calc_subject_state_instances_name(p_subject_state_instance_id TEXT)
RETURNS TEXT AS $$
  SELECT ((SELECT NULLIF(subject_state_instance_id, '') FROM subject_state_instances WHERE subject_state_instance_id = p_subject_state_instance_id))::text;
$$ LANGUAGE sql STABLE;

-- calc_subject_state_instances_is_current
-- Field: SubjectStateInstances.IsCurrent
-- Type: calculated | DataType: boolean | Returns: BOOLEAN


CREATE OR REPLACE FUNCTION calc_subject_state_instances_is_current(p_subject_state_instance_id TEXT)
RETURNS BOOLEAN AS $$
  SELECT ((((SELECT exited_at::timestamptz FROM subject_state_instances WHERE subject_state_instance_id = p_subject_state_instance_id)) IS NULL OR ((SELECT exited_at::timestamptz FROM subject_state_instances WHERE subject_state_instance_id = p_subject_state_instance_id))::text = ''))::boolean;
$$ LANGUAGE sql STABLE;

-- calc_subject_state_instances_has_complete_lineage
-- Field: SubjectStateInstances.HasCompleteLineage
-- Type: calculated | DataType: boolean | Returns: BOOLEAN


CREATE OR REPLACE FUNCTION calc_subject_state_instances_has_complete_lineage(p_subject_state_instance_id TEXT)
RETURNS BOOLEAN AS $$
  SELECT (((SELECT sequence_index FROM subject_state_instances WHERE subject_state_instance_id = p_subject_state_instance_id))::NUMERIC >= 1)::boolean;
$$ LANGUAGE sql STABLE;

-- calc_violation_types_jurisdiction_label
-- Field: ViolationTypes.JurisdictionLabel
-- Type: lookup | DataType: string | Returns: TEXT
-- Lookup: DisplayName from related Jurisdictions


CREATE OR REPLACE FUNCTION calc_violation_types_jurisdiction_label(p_violation_type_id TEXT)
RETURNS TEXT AS $$
  SELECT (SELECT display_name::text FROM jurisdictions WHERE jurisdiction_id = (SELECT jurisdiction FROM violation_types WHERE violation_type_id = p_violation_type_id));
$$ LANGUAGE sql STABLE;

-- calc_violation_types_traffic_school_point_cap
-- Field: ViolationTypes.TrafficSchoolPointCap
-- Type: lookup | DataType: integer | Returns: INTEGER
-- Lookup: TrafficSchoolPointCap from related Jurisdictions


CREATE OR REPLACE FUNCTION calc_violation_types_traffic_school_point_cap(p_violation_type_id TEXT)
RETURNS INTEGER AS $$
  SELECT (SELECT traffic_school_point_cap::integer FROM jurisdictions WHERE jurisdiction_id = (SELECT jurisdiction FROM violation_types WHERE violation_type_id = p_violation_type_id));
$$ LANGUAGE sql STABLE;

-- calc_violation_types_name
-- Field: ViolationTypes.Name
-- Type: calculated | DataType: string | Returns: TEXT


CREATE OR REPLACE FUNCTION calc_violation_types_name(p_violation_type_id TEXT)
RETURNS TEXT AS $$
  SELECT (REPLACE(LOWER((SELECT NULLIF(code, '') FROM violation_types WHERE violation_type_id = p_violation_type_id)), ' ', '-'))::text;
$$ LANGUAGE sql STABLE;

-- calc_violation_types_is_school_eligible_by_cap
-- Field: ViolationTypes.IsSchoolEligibleByCap
-- Type: calculated | DataType: boolean | Returns: BOOLEAN


CREATE OR REPLACE FUNCTION calc_violation_types_is_school_eligible_by_cap(p_violation_type_id TEXT)
RETURNS BOOLEAN AS $$
  SELECT (CASE WHEN (SELECT points FROM violation_types WHERE violation_type_id = p_violation_type_id) <= calc_violation_types_traffic_school_point_cap(p_violation_type_id) THEN TRUE ELSE FALSE END)::boolean;
$$ LANGUAGE sql STABLE;

-- calc_violation_types_count_of_citations
-- Field: ViolationTypes.CountOfCitations
-- Type: aggregation | DataType: integer | Returns: INTEGER


CREATE OR REPLACE FUNCTION calc_violation_types_count_of_citations(p_violation_type_id TEXT)
RETURNS INTEGER AS $$
  SELECT ((SELECT COUNT(*) FROM citations WHERE violation_type = calc_violation_types_name(p_violation_type_id)))::integer;
$$ LANGUAGE sql STABLE;

