$$ LANGUAGE sql STABLE;

-- calc_drivers_name
-- Field: Drivers.Name
-- Type: calculated | DataType: string | Returns: TEXT


CREATE OR REPLACE FUNCTION calc_drivers_name(p_driver_id TEXT)
RETURNS TEXT AS $$
  SELECT (REPLACE(LOWER((SELECT NULLIF(license_number, '') FROM drivers WHERE driver_id = p_driver_id)), ' ', '-'))::text;
$$ LANGUAGE sql STABLE;

-- calc_drivers_full_name
-- Field: Drivers.FullName
-- Type: calculated | DataType: string | Returns: TEXT


CREATE OR REPLACE FUNCTION calc_drivers_full_name(p_driver_id TEXT)
RETURNS TEXT AS $$
  SELECT (CONCAT((SELECT NULLIF(last_name, '') FROM drivers WHERE driver_id = p_driver_id), ', ', (SELECT NULLIF(first_name, '') FROM drivers WHERE driver_id = p_driver_id)))::text;
$$ LANGUAGE sql STABLE;

-- calc_drivers_count_of_citations
-- Field: Drivers.CountOfCitations
-- Type: aggregation | DataType: integer | Returns: INTEGER


CREATE OR REPLACE FUNCTION calc_drivers_count_of_citations(p_driver_id TEXT)
RETURNS INTEGER AS $$
  SELECT ((SELECT COUNT(*) FROM citations WHERE driver = calc_drivers_name(p_driver_id)))::integer;
$$ LANGUAGE sql STABLE;

-- calc_drivers_active_points
-- Field: Drivers.ActivePoints
-- Type: aggregation | DataType: integer | Returns: INTEGER


CREATE OR REPLACE FUNCTION calc_drivers_active_points(p_driver_id TEXT)
RETURNS INTEGER AS $$
  SELECT ((SELECT COALESCE(SUM((calc_citations_effective_points(citation_id))::numeric), 0) FROM citations WHERE driver = calc_drivers_name(p_driver_id)))::integer;
$$ LANGUAGE sql STABLE;

-- calc_drivers_license_status
-- Field: Drivers.LicenseStatus
-- Type: calculated | DataType: string | Returns: TEXT


CREATE OR REPLACE FUNCTION calc_drivers_license_status(p_driver_id TEXT)
RETURNS TEXT AS $$
  SELECT (CASE WHEN calc_drivers_active_points(p_driver_id) >= calc_drivers_suspension_threshold(p_driver_id) THEN ('Suspended')::text ELSE (CASE WHEN calc_drivers_active_points(p_driver_id) >= calc_drivers_warning_threshold(p_driver_id) THEN ('Warning')::text ELSE ('Valid')::text END)::text END)::text;
$$ LANGUAGE sql STABLE;

-- calc_citations_driver_label
