-- Lookup: FullName from related Drivers


CREATE OR REPLACE FUNCTION calc_citations_driver_label(p_citation_id TEXT)
RETURNS TEXT AS $$
  SELECT calc_drivers_full_name((SELECT driver FROM citations WHERE citation_id = p_citation_id));
$$ LANGUAGE sql STABLE;

