-- Field: BuildPhases.Name
-- Type: calculated | DataType: string | Returns: TEXT


CREATE OR REPLACE FUNCTION calc_build_phases_name(p_build_phase_id TEXT)
RETURNS TEXT AS $$
  SELECT ((SELECT NULLIF(build_phase_id, '') FROM build_phases WHERE build_phase_id = p_build_phase_id))::text;
$$ LANGUAGE sql STABLE;

